import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.CnqOxlWO.js";const u=JSON.parse('{"title":"Telegram Integration","description":"","frontmatter":{},"headers":[],"relativePath":"features/telegram.md","filePath":"features/telegram.md","lastUpdated":1773376681000}'),s={name:"features/telegram.md"};function i(l,e,r,h,d,c){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="telegram-integration" tabindex="-1">Telegram Integration <a class="header-anchor" href="#telegram-integration" aria-label="Permalink to &quot;Telegram Integration&quot;">​</a></h1><p>If you want people to chat with your agent directly on Telegram, you need to connect a Telegram channel.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before configuring, you need a Telegram Bot Token.</p><h3 id="how-to-get-a-bot-token" tabindex="-1">How to Get a Bot Token <a class="header-anchor" href="#how-to-get-a-bot-token" aria-label="Permalink to &quot;How to Get a Bot Token&quot;">​</a></h3><ol><li>Open Telegram and search for <code>@BotFather</code>.</li><li>Send <code>/newbot</code>.</li><li>Follow the prompts to set a bot name and username.</li><li>Copy the Bot Token that BotFather returns.</li></ol><p>A Bot Token looks like this:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>123456789:ABCdefGHIjklMNOpqrsTUVwxyz</span></span></code></pre></div><p>Keep this token private. Do not share it publicly.</p><h2 id="connecting-in-clawdsaber" tabindex="-1">Connecting in ClawdSaber <a class="header-anchor" href="#connecting-in-clawdsaber" aria-label="Permalink to &quot;Connecting in ClawdSaber&quot;">​</a></h2><ol><li>In the sidebar, find the agent you want to connect.</li><li>Click the <strong>Settings</strong> icon on that agent.</li><li>Go to the <strong>Channels</strong> tab.</li><li>Click <strong>Add Channel</strong>.</li><li>Select <strong>Telegram</strong>.</li><li>Fill in the form:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Bot Token</strong></td><td>The token from <code>@BotFather</code></td></tr><tr><td><strong>Allowed Users</strong></td><td>Comma-separated Telegram usernames (no <code>@</code> prefix)</td></tr></tbody></table><h2 id="allowed-users-format" tabindex="-1">Allowed Users Format <a class="header-anchor" href="#allowed-users-format" aria-label="Permalink to &quot;Allowed Users Format&quot;">​</a></h2><h3 id="allow-everyone" tabindex="-1">Allow Everyone <a class="header-anchor" href="#allow-everyone" aria-label="Permalink to &quot;Allow Everyone&quot;">​</a></h3><p>Enter:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>*</span></span></code></pre></div><h3 id="allow-specific-users" tabindex="-1">Allow Specific Users <a class="header-anchor" href="#allow-specific-users" aria-label="Permalink to &quot;Allow Specific Users&quot;">​</a></h3><p>Enter Telegram usernames separated by commas, without the <code>@</code> symbol:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>alice,bob,charlie</span></span></code></pre></div><h2 id="what-happens-after-saving" tabindex="-1">What Happens After Saving <a class="header-anchor" href="#what-happens-after-saving" aria-label="Permalink to &quot;What Happens After Saving&quot;">​</a></h2><p>When you save, the app validates the Bot Token.</p><p>On success:</p><ul><li>A confirmation message appears</li><li>The bot&#39;s username is displayed</li><li>The channel appears in the channel list</li></ul><p>On failure, the error message is shown directly on the form.</p><h2 id="testing-the-connection" tabindex="-1">Testing the Connection <a class="header-anchor" href="#testing-the-connection" aria-label="Permalink to &quot;Testing the Connection&quot;">​</a></h2><ol><li>Open Telegram and search for your bot.</li><li>Click <strong>Start</strong> or send any message.</li><li>Check whether the agent responds.</li></ol><p>If you restricted allowed users, make sure your Telegram username is in the list.</p><h2 id="common-issues" tabindex="-1">Common Issues <a class="header-anchor" href="#common-issues" aria-label="Permalink to &quot;Common Issues&quot;">​</a></h2><h3 id="bot-token-is-invalid" tabindex="-1">Bot Token is invalid <a class="header-anchor" href="#bot-token-is-invalid" aria-label="Permalink to &quot;Bot Token is invalid&quot;">​</a></h3><ul><li>Confirm the token was copied from <code>@BotFather</code>.</li><li>Check for extra spaces or line breaks.</li><li>Verify that the bot was created successfully in Telegram.</li></ul><h3 id="allowed-users-setting-does-not-work" tabindex="-1">Allowed users setting does not work <a class="header-anchor" href="#allowed-users-setting-does-not-work" aria-label="Permalink to &quot;Allowed users setting does not work&quot;">​</a></h3><ul><li>Make sure usernames are separated by commas (not spaces or semicolons).</li><li>Do not include the <code>@</code> prefix.</li><li>Verify that the Telegram username you are testing with matches exactly.</li></ul><h3 id="bot-is-connected-but-does-not-reply" tabindex="-1">Bot is connected but does not reply <a class="header-anchor" href="#bot-is-connected-but-does-not-reply" aria-label="Permalink to &quot;Bot is connected but does not reply&quot;">​</a></h3><p>Check the following in order:</p><ol><li>The agent has a model assigned (see <a href="/clawdsaber-docs/features/agent-config.html">Agent Configuration</a>).</li><li>The Gateway is running.</li><li>Your account has sufficient credits.</li></ol><p>If none of that helps, see the <a href="/clawdsaber-docs/settings/faq.html">FAQ</a>.</p>',36)])])}const g=t(s,[["render",i]]);export{u as __pageData,g as default};
